class Solution:
    def minimumDifference(self, nums, k):
        n = len(nums)
        best = float('inf')
        for i in range(n):
            cur = 0
            for j in range(i, n):
                cur |= nums[j]
                best = min(best, abs(cur - k))
                if cur >= k:
                    break
        return best

