class Solution:
    def minimumDifference(self, nums, k):
        best = float('inf')
        prev = set()
        for num in nums:
            curr = {num}
            for v in prev:
                curr.add(v | num)
            for v in curr:
                best = min(best, abs(v - k))
            prev = curr
        return best

