var minimumDifference = function(nums, k) {
    let best = Infinity;
    let prev = new Set();
    for (const num of nums) {
        const curr = new Set([num]);
        for (const v of prev) curr.add(v | num);
        for (const v of curr) {
            const diff = Math.abs(v - k);
            if (diff < best) best = diff;
        }
        prev = curr;
    }
    return best;
};
